powershell # Windows PowerShell Script for n8n Environment Setup Write-Host "========================================" -ForegroundColor Cyan Write-Host " Starting n8n Environment Setup (Windows)" -ForegroundColor Cyan Write-Host "========================================" -ForegroundColor Cyan if (Test-Path ".env.example") { Copy-Item ".env.example" -Destination ".env" Write-Host "[SUCCESS] n8n Configuration file (.env) generated." -ForegroundColor Green } else { Write-Host "[ERROR] Template file not found!" -ForegroundColor Red }